const express = require('express');
const bodyParser = require('body-parser');
const path = require('path');
const fs = require('fs');
const port = process.env.PORT || 3000;

const app = express();

app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'index.html'));
});

app.get('/api/health', (req, res) => {
  res.send({ status: 'ok' });
});

app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

:root {
  --warm-white: #fdf8f0;
  --deep-brown: #452b1f;
  --amber: #ffc107;
  --spacing: 16px;
  --radius: 16px;
}

body {
  font-family: 'Open Sans', sans-serif;
  background-color: var(--warm-white);
  margin: 0;
  padding: 0;
}

header {
  background-color: var(--deep-brown);
  color: var(--warm-white);
  padding: 16px;
  text-align: center;
}

nav ul {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  justify-content: space-between;
}

nav li {
  margin-right: 16px;
}

nav a {
  color: var(--warm-white);
  text-decoration: none;
}

main {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 16px;
}

section {
  background-color: var(--warm-white);
  padding: 16px;
  border-radius: var(--radius);
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
  margin-bottom: 16px;
}

h2 {
  margin-top: 0;
}

#history-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

#history-list li {
  padding: 8px;
  border-bottom: 1px solid #ccc;
}

#history-list li:last-child {
  border-bottom: none;
}

#output-container {
  padding: 16px;
  border-radius: var(--radius);
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
  background-color: var(--warm-white);
}

#run-button, #clear-button, #undo-button, #download-button {
  background-color: var(--amber);
  color: var(--deep-brown);
  padding: 8px 16px;
  border: none;
  border-radius: var(--radius);
  cursor: pointer;
}

#run-button:hover, #clear-button:hover, #undo-button:hover, #download-button:hover {
  background-color: var(--deep-brown);
  color: var(--warm-white);
}

#run-button:active, #clear-button:active, #undo-button:active, #download-button:active {
  transform: scale(0.96);
}

::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-thumb {
  background-color: var(--deep-brown);
  border-radius: var(--radius);
}

::-webkit-scrollbar-track {
  background-color: var(--warm-white);
}

::selection {
  background-color: var(--amber);
  color: var(--deep-brown);
}

const historyList = document.getElementById('history-list');
const outputContainer = document.getElementById('output-container');
const runButton = document.getElementById('run-button');
const clearButton = document.getElementById('clear-button');
const undoButton = document.getElementById('undo-button');
const downloadButton = document.getElementById('download-button');
const inputField = document.getElementById('input-field');
const history = JSON.parse(localStorage.getItem('history')) || [];

inputField.addEventListener('input', debounce(() => {
  const output = inputField.value;
  outputContainer.innerText = output;
  history.push(output);
  localStorage.setItem('history', JSON.stringify(history));
  renderHistory();
}, 150));

runButton.addEventListener('click', () => {
  const output = inputField.value;
  console.log(output);
});

clearButton.addEventListener('click', () => {
  inputField.value = '';
  outputContainer.innerText = '';
  history.length = 0;
  localStorage.setItem('history', JSON.stringify(history));
  renderHistory();
});

undoButton.addEventListener('click', () => {
  if (history.length > 0) {
    history.pop();
    localStorage.setItem('history', JSON.stringify(history));
    renderHistory();
  }
});

downloadButton.addEventListener('click', () => {
  const blob = new Blob([inputField.value], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'output.txt';
  a.click();
  URL.revokeObjectURL(url);
});

function renderHistory() {
  historyList.innerHTML = '';
  history.forEach((item, index) => {
    const li = document.createElement('li');
    li.textContent = item;
    li.style.padding = '8px';
    li.style.borderBottom = '1px solid #ccc';
    if (index === history.length - 1) {
      li.style.borderBottom = 'none';
    }
    historyList.appendChild(li);
  });
}

function debounce(func, wait) {
  let timeout;
  return function() {
    const context = this;
    const args = arguments;
    clearTimeout(timeout);
    timeout = setTimeout(() => {
      func.apply(context, args);
    }, wait);
  };
}

window.addEventListener('hashchange', () => {
  const hash = window.location.hash;
  if (hash === '#history') {
    historyList.scrollIntoView();
  } else if (hash === '#output') {
    outputContainer.scrollIntoView();
  }
});

document.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') {
    runButton.click();
  } else if (e.key === 'Escape') {
    clearButton.click();
  } else if (e.key === 'z' && e.ctrlKey) {
    undoButton.click();
  }
});
